  4→const analysisSteps = [
  5→  { icon: Globe, label: 'Crawl du site web...', duration: 2000 },
  6→  { icon: Bot, label: 'Interrogation des IA (ChatGPT, Claude, Gemini, AI Overviews)...', duration: 3000 },
  7→  { icon: BarChart3, label: 'Analyse des 50+ critères AEO...', duration: 2500 },
  8→  { icon: CheckCircle, label: 'Génération du rapport...', duration: 1500 },
  9→];
 10→
 11→interface AnalyzeProps {
 12→  onAnalyze: (url: string) => void;
 13→  isAnalyzing: boolean;
 14→}
 15→
 16→const Analyze: React.FC<AnalyzeProps> = ({ onAnalyze, isAnalyzing }) => {
 17→  const [inputUrl, setInputUrl] = useState('');
 18→  const [currentStep, setCurrentStep] = useState(0);
 19→
 20→  useEffect(() => {
 21→    if (!isAnalyzing) { setCurrentStep(0); return; }
 22→    let step = 0;
 23→    setCurrentStep(0);
 24→    const timers: ReturnType<typeof setTimeout>[] = [];
 25→    let accumulated = 0;
 26→    analysisSteps.forEach((s, i) => {
 27→      if (i > 0) {
 28→        accumulated += analysisSteps[i - 1].duration;
 29→        timers.push(setTimeout(() => setCurrentStep(i), accumulated));
 30→      }
 31→    });
 32→    return () => timers.forEach(clearTimeout);
 33→  }, [isAnalyzing]);
 34→
 35→  const handleSubmit = (e: React.FormEvent) => {
 36→    e.preventDefault();
 37→    if (inputUrl && !isAnalyzing) {
 38→      onAnalyze(inputUrl);
 39→    }
 40→  };
 41→
 42→  return (
 43→    <div className="w-full px-4 min-h-[80vh] flex flex-col items-center justify-center animate-in fade-in duration-500">
 44→      
 45→      <div className="text-center mb-10 space-y-4">
 46→        <div className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full bg-white/[0.04] border border-white/[0.08] text-purple-400 text-sm font-medium">
 47→          <Sparkles size={14} />
 48→          <span>Audit AEO & GEO Instantané</span>
 49→        </div>
 50→        <h1 className="text-4xl md:text-5xl font-sans font-bold text-white">
 51→          Analysez votre <span className="gradient-text">visibilité IA</span>
 52→        </h1>
 53→        <p className="text-xl text-gray-500 max-w-2xl mx-auto">
 54→          Découvrez comment les moteurs de réponse perçoivent votre contenu et obtenez un plan d'action pour être cité.
 55→        </p>
 56→      </div>
 57→
 58→      <div className="w-full max-w-3xl relative z-10">
 59→        <div className="absolute inset-0 bg-primary/20 blur-3xl rounded-full opacity-20 -z-10"></div>
 60→        <form onSubmit={handleSubmit}>
 61→          <div className="ninja-card p-8">
 62→            <div className="flex items-center gap-3">
 63→              <Search className="text-gray-500 shrink-0" size={24} />
 64→              <input
 65→                type="url"
 66→                required
 67→                placeholder="https://votre-site.com"
 68→                className="w-full bg-[#111111] border border-white/[0.08] rounded-xl focus:ring-1 focus:ring-purple-500/30 focus:border-purple-500/30 text-white placeholder-gray-500 text-lg px-4 py-4"
 69→                value={inputUrl}
 70→                onChange={(e) => setInputUrl(e.target.value)}
 71→                autoFocus
 72→              />
 73→              <button
 74→                type="submit"
 75→                disabled={isAnalyzing}
 76→                className={`btn-gradient px-8 py-4 shrink-0 transition-all transform hover:scale-105 ${isAnalyzing ? '!bg-gray-600 cursor-not-allowed opacity-60' : ''}`}
 77→              >
 78→                {isAnalyzing ? 'Analyse...' : 'Lancer l\'audit'}
 79→              </button>
 80→            </div>
 81→          </div>
 82→        </form>
 83→        
 84→        {!isAnalyzing && (
 85→          <div className="flex justify-center gap-8 mt-8 text-sm text-gray-500">
 86→            <span className="flex items-center gap-2"><ShieldCheck size={16} className="text-purple-400"/> Analyse Sécurisée</span>
 87→            <span className="flex items-center gap-2"><TrendingUp size={16} className="text-purple-400"/> +50 Critères GEO</span>
 88→          </div>
 89→        )}
 90→
 91→        {isAnalyzing && (
 92→          <div className="mt-8 w-full max-w-md mx-auto space-y-3 animate-in fade-in duration-300">
 93→            {analysisSteps.map((step, i) => {
 94→              const StepIcon = step.icon;
 95→              const isActive = i === currentStep;
 96→              const isDone = i < currentStep;
 97→              return (
 98→                <div key={i} className={`flex items-center gap-3 px-4 py-3 rounded-xl transition-all duration-500 ${
 99→                  isActive ? 'bg-purple-500/10 border border-purple-500/20' : isDone ? 'bg-white/[0.02] border border-white/[0.04]' : 'opacity-40 border border-transparent'
100→                }`}>
101→                  <div className={`w-8 h-8 rounded-full flex items-center justify-center shrink-0 transition-all duration-300 ${
102→                    isDone ? 'bg-emerald-500/20' : isActive ? 'bg-purple-500/20' : 'bg-white/[0.04]'
103→                  }`}>
104→                    {isDone ? <CheckCircle size={16} className="text-emerald-400" /> : <StepIcon size={16} className={isActive ? 'text-purple-400 animate-pulse' : 'text-gray-600'} />}
105→                  </div>
106→                  <span className={`text-sm font-medium transition-colors duration-300 ${isDone ? 'text-emerald-400' : isActive ? 'text-purple-300' : 'text-gray-600'}`}>{step.label}</span>
107→                  {isActive && <div className="ml-auto w-4 h-4 border-2 border-purple-400 border-t-transparent rounded-full animate-spin" />}
108→                </div>
109→              );
110→            })}
111→            <div className="mt-4 w-full h-1.5 bg-white/[0.06] rounded-full overflow-hidden">
112→              <div className="h-full bg-gradient-to-r from-purple-500 to-violet-500 rounded-full transition-all duration-1000 ease-out" style={{ width: `${((currentStep + 1) / analysisSteps.length) * 100}%` }} />
113→            </div>
114→          </div>
115→        )}
116→      </div>
117→
118→    </div>
119→  );
120→};
121→
122→export default Analyze;

