 268→
 269→    // Définir le début du cycle de facturation (simulé au 1er du mois courant)
 270→    const now = new Date();
 271→    const billingCycleStart = new Date(now.getFullYear(), now.getMonth(), 1);
 272→
 273→    // 1. Identifier la date de création (première analyse) de chaque domaine
 274→    const projectCreationDates = new Map<string, Date>();
 275→    
 276→    history.forEach(h => {
 277→        let hostname;
 278→        try { hostname = new URL(h.url).hostname; } catch(e) { hostname = h.url; }
 279→        
 280→        const analysisDate = new Date(h.timestamp);
 281→        
 282→        if (!projectCreationDates.has(hostname)) {
 283→            projectCreationDates.set(hostname, analysisDate);
 284→        } else {
 285→            // On garde la date la plus ancienne trouvée pour ce domaine
 286→            if (analysisDate < projectCreationDates.get(hostname)!) {
 287→                projectCreationDates.set(hostname, analysisDate);
 288→            }
 289→        }
 290→    });
 291→
 292→    // 2. Compter uniquement les projets dont la "création" est postérieure au début du cycle
 293→    let count = 0;
 294→    projectCreationDates.forEach((creationDate) => {
 295→        if (creationDate >= billingCycleStart) {
 296→            count++;
 297→        }
 298→    });
 299→    
 300→    return count;
 301→  }, [history]);
