 432→  const handleSaveSolution = useCallback((analysisId: string, recommendationId: string, solution: GeneratedSolution) => {
 433→    const timestamp = new Date().toISOString();
 434→    const solutionWithMeta = { ...solution, timestamp };
 435→
 436→    setAnalysisData(prev => {
