 440→            ...prev,
 441→            generatedSolutions: {
 442→                ...(prev.generatedSolutions || {}),
 443→                [recommendationId]: solutionWithMeta
 444→            }
 445→        };
 446→    });
 447→
 448→    // We need to find the index in the history to update the DB
 449→    setHistory(prevHistory => {
 450→        const index = prevHistory.findIndex(item => item.timestamp === analysisId);
 451→        if (index !== -1) {
 452→            const updatedItem = {
 453→                ...prevHistory[index],
 454→                generatedSolutions: {
 455→                    ...(prevHistory[index].generatedSolutions || {}),
 456→                    [recommendationId]: solutionWithMeta
 457→                }
 458→            };
 459→            // Persist using db service
 460→            const newHistory = [...prevHistory];
 461→            newHistory[index] = updatedItem;
 462→            // Note: calling db.update relies on index which matches prevHistory order if initialized from DB
 463→            db.update(index, updatedItem);
 464→            return newHistory;
 465→        }
 466→        return prevHistory;
 467→    });
 468→  }, []); 
