    }));
  }
}, [history]);
```

**SourceOfTruth.tsx (lines 26-73):**
```typescript
const extractDataFromUrl = (url: string): SourceOfTruthData => {
  // Extract hostname, name, generate dummy data
  return {
    description: `${name} est une référence...`,
    type: 'Entreprise de services numériques',
    founded: '2020',
    location: 'Paris, France',
    services: [...],
    faqs: [...]
  };
};

// Use latest analysis or fallback to defaults
const [data, setData] = useState<SourceOfTruthData>(() => {
  if (history.length > 0) {
    return extractDataFromUrl(history[0].url);
  }
  return { /* default empty state */ };
