```

**SMCStudio.tsx (lines 1-14 props):**
- Does NOT require history prop
- Generates SMC content independently
- Has library state for saving generated items

**RobotsTxt.tsx (lines 28-61):**
```typescript
useEffect(() => {
  const processUrl = (analysis: AnalysisResult | undefined) => {
    if (!analysis) {
      // Demo mode
      const demoUrl = "https://monsite-wordpress.com";
      setCurrentContent(parseCurrentRobotsTxt(demoUrl));
      setOptimizedContent(generateOptimizedRobotsTxt(demoUrl));
      return;
    }

    // Real analysis mode
