      setOptimizedContent(generateOptimizedRobotsTxt(url));
      setIsUnlocked(false);
    }
  };

  if (history.length > 0) {
    processUrl(history[selectedAnalysisIndex]);
  } else {
    processUrl(undefined); // Demo mode
  }
}, [selectedAnalysisIndex, history]);
```

