**Path 2: Saving Solution to History (`App.tsx` lines 432-468)**
```typescript
const handleSaveSolution = useCallback((analysisId, recId, solution) => {
  // 1. Add timestamp to solution
  const solutionWithMeta = { ...solution, timestamp };

  // 2. Update analysisData state
  setAnalysisData(prev => ({
    ...prev,
    generatedSolutions: {
      ...(prev.generatedSolutions || {}),
      [recId]: solutionWithMeta
    }
  }));

  // 3. Find and update history array
  setHistory(prevHistory => {
    const index = prevHistory.findIndex(item => item.timestamp === analysisId);
    if (index !== -1) {
      const updatedItem = { ...prevHistory[index], generatedSolutions: {...} };
      db.update(index, updatedItem); // Persist to localStorage
      return newHistory;
    }
    return prevHistory;
  });
});
```

